// SPDX-License-Identifier: MIT
pragma solidity ^0.8.3;

// TODO: Add better error handling
contract ReputationCalculation {
    address public complaintRegistry;

    mapping(uint => uint) public totalScore;
    mapping(uint => uint) public reviewCount;
    mapping(uint256 => mapping(address => bool)) public hasRated;
    mapping(uint256 => mapping(address => uint256)) public userRating;

    event ScoreAdded(uint256 indexed orgId, address indexed user, uint256 score);
    event ScoreUpdated(uint256 indexed orgId, address indexed user, uint256 oldScore, uint256 newScore);

    modifier onlyComplaintRegistry() {
        require(msg.sender == complaintRegistry, "Only ComplaintRegistry can call");
        _;
    }

    constructor() {
        complaintRegistry = msg.sender;
    }

    function updateExistingScore (uint orgId, address user, uint newScore) private 
        returns (uint oldScore) 
    {
        oldScore = userRating[orgId][user];
        totalScore[orgId] = totalScore[orgId] - oldScore + newScore;
        userRating[orgId][user] = newScore;
        return oldScore;
    }

    function updateScore (uint orgId, address user, uint score) public {
        require(score >= 1 && score <= 10, "Score must be between 1 and 10");

        if (hasRated[orgId][user]) {
            uint oldScore = updateExistingScore(orgId, user, score);

            emit ScoreUpdated(orgId, user, oldScore, score);
        } else {
            totalScore[orgId] += score;
            reviewCount[orgId] +1;
            hasRated[orgId][user] = true;
            userRating[orgId][user] = score;

            emit ScoreAdded(orgId, user, score);
        }
    }

    // TODO: FIND A BETTER SCORE CALCULATION SYSTEM (ELO LIKE?)
    function getScore(uint orgId) public view returns (uint) {
        if (reviewCount[orgId] == 0) { return 0; }
        return totalScore[orgId] / reviewCount[orgId];
    }

    //TODO: ADD GET TOP SCORES
}

